final:
module top_module(
    input  D,
    output Q,
    input  RESET,
    input  SET,
    input  CLK_N
);reg obf_Q_reg;

always @ (negedge CLK_N) begin
    if (RESET) begin
        obf_Q_reg <= 0;
    end else if (SET) begin
        obf_Q_reg <= 1;
    end else begin
        obf_Q_reg <= D;
    end
end

assign Q = obf_Q_reg;

endmodule
